'use client';

export default function SwipeIndicator() {
  return (
    <div className='absolute bottom-15 left-1/2 -translate-x-1/2 z-20 flex items-center justify-center'>
      <div className="relative w-10 h-16 rounded-full border border-black/30 bg-white/5 backdrop-blur-md shadow-[0_0_20px_rgba(234, 15, 15, 0.819)]">
        {/* Static inner bar */}
        <div className='absolute left-1/2 top-2 -translate-x-1/2 w-1.5 h-4 rounded bg-black/40' />

        {/* Animated dot */}
        <div className='absolute left-1/2 top-2 -translate-x-1/2 w-1.5 h-1.5 rounded-full bg-black animate-swipe' />
      </div>
    </div>
  );
}
